import { type Database, ReadOnly } from "./database";
import * as repl from "../replicator/replicator";
import { assert } from "@/util/assert";
import * as blob from "@/blob/blob";
import type * as logtape from "@logtape/logtape";
import type { DocID, RevID, Revision } from "./types";
import type { Collection } from "./collection";
import { greaterGeneration, revIsDeleted, type LocalRevision } from "./internals";
import type { JSONObject, ListenerToken } from "@/couchbase-lite";
import { sha1 } from "sha.js";

export type { Credentials, CheckpointerDelegate, PusherConfig, PullerConfig, PullConflictResolver,
    RemoteRevisionInfo, ReplicatorError, Status } from "../replicator/replicator";


/** Configuration for {@link Replicator}.
 *  @interface
 *  @property database  The Database to sync.
 *  @property url  Server URL to connect to, with scheme "wss:" or "ws:", and database name
 *                 as first path component.
 *  @property collections  Keys are names of collections to sync;
 *                         values are per-collection configuration. */
export interface ReplicatorConfig {
    database    : Database,
    url         : string,
    credentials?: repl.Credentials,
    collections : Record<string, ReplicatorCollectionConfig>,
}


/** Per-collection Replicator configuration.
 *  @property push  Configuration for pushing. If not present, replicator will not push.
 *  @property pull  Configuration for pulling. If not present, replicator will not pull.
 *  @property documentIDs  If set, only these documents will be pushed or pulled.
 *  @property resetCheckpoint  If true, the replicator will ignore its current state and compare
*                              all document revision IDs with the server.  */
export interface ReplicatorCollectionConfig {
    push?               : repl.PusherConfig,
    pull?               : repl.PullerConfig,
    documentIDs?        : readonly DocID[],
    resetCheckpoint?    : boolean,
}


/** Information about a document that's been pushed or pulled by a replicator.
 *  @see {@link Replicator.onDocuments} */
export interface DocumentEnded {
    docID       : DocID,
    deleted?    : boolean,
    lostAccess? : repl.LostAccess,
    error?      : Error,
}


/** Syncs one or more {@link Collection}s with their remote counterparts. */
export class Replicator implements repl.CheckpointerDelegate {

    constructor(private config: ReplicatorConfig) {
        this.database = config.database;
        this.logger = repl.SyncLogger.with({url: config.url});
        const ids = Object.keys(this.config.collections);
        assert(ids.length > 0, "At least one collection must be replicated");
        for (const id of ids)
            void(this.database.getCollection(id));  // just verify it exists
    }

    /** The local database being replicated. */
    readonly database: Database;

    /** Callback that notifies when {@link status} changes. */
    onStatusChange? : (status: repl.Status) => void;

    /** Callback that notifies when documents have been pushed or pulled.
     *
     * Note: To receive lost-access (revocation) notifications from the pull replicator
     * when auto-purge is disabled, this callback must be registered *before*
     * starting the pull replicator. */
    onDocuments? : (collection: Collection, direction: 'push' | 'pull', documents: DocumentEnded[]) => void;


    /** Current replication status & progress. */
    get status(): repl.Status {return this.#replicator?.status ?? this.#lastStatus;}


    /** Runs the replicator.
     *
     * This is an async operation. The returned Promise resolves when the replication completes.
     * A continuous replication usually _never_ completes, unless it encounters a fatal error or
     * you stop it, so you may not want to `await` it. */
    async run() {
        assert(!this.#replicator, "Replicator is already running");

        const redactedCfg = {
            database    : this.config.database.name,
            url         : this.config.url,
            credentials : this.config.credentials ? {username: this.config.credentials.username} : undefined,
            collections : this.config.collections,
        };
        this.logger.info `Starting replicator with configuration: ${redactedCfg}`;

        // Construct actual replicator config:
        let replCfg: repl.ReplicatorConfig = {
            url: this.config.url,
            credentials: this.config.credentials,
            collections: {},
        };
        for (let id of Object.keys(this.config.collections)) {
            const collCfg = this.config.collections[id];
            const collection = this.database.getCollection(id);
            const clientID = await this.getCheckpointID(collection);
            const reset = collCfg.resetCheckpoint;
            const initialCheckpoint = reset ? undefined : await collection.getCheckpoint(clientID);

            let replCollCfg: repl.CollectionConfig = {
                checkpoint: {clientID, initialCheckpoint, reset, delegate: this}
            };
            if (collCfg.pull) {
                const startedEmpty = await collection.count('includeDeleted') === 0;
                const delegate = new PullerDelegateImpl(this, collection, collCfg.pull, startedEmpty);
                replCollCfg.pull = {...collCfg.pull, documentIDs: collCfg.documentIDs, delegate};
                if (startedEmpty)
                    replCollCfg.pull.activeOnly = true;
            }
            if (collCfg.push) {
                const delegate = new PusherDelegateImpl(this, collection, collCfg.push);
                replCollCfg.push = {...collCfg.push, documentIDs: collCfg.documentIDs, delegate};
            }
            replCfg.collections[id as repl.CollectionID] = replCollCfg;
        }

        // Now run the Replicator:
        this.#replicator = new repl.Replicator(replCfg);
        this.#replicator.onStatusChange = this.onStatusChange;
        try {
            await this.#replicator.run();
        } finally {
            this.#lastStatus = this.#replicator.status;
            this.#replicator = undefined;
        }

        this.logger.info `FINISHED! ${JSON.stringify(this.status)}`;
    }


    /** Stops the replicator. The current {@link run} operation's Promise will resolve with
     *  an error as soon as possible.
     *
     *  Does nothing if `run` is not active. */
    stop() {
        this.#replicator?.stop();
    }


    /** Returns the checkpoint ID that will be used for a collection. @internal */
    async getCheckpointID(collection: Collection): Promise<string> {
        const cfg = this.config.collections[collection.name];
        const hashed = [
            await collection.getUUID(),             // Collection ID
            this.config.url,                        // Remote database URL
            cfg.documentIDs?.toSorted() ?? null,    // Documents filter
            cfg.pull?.channels?.toSorted() ?? null, // Channel filter
            !!cfg.pull?.filter,                     // Custom pull filter present (boolean)
            !!cfg.push?.filter,                     // Custom push filter present (boolean)
        ];
        return new sha1().update(JSON.stringify(hashed)).digest('base64');
    }


    //-------- Checkpointer delegate implementation

    /** Saves a checkpoint to the local database. @internal */
    async saveCheckpoint(id: repl.CollectionID, clientID: string, checkpoint: repl.Checkpoint): Promise<void> {
        await this.database.getCollection(id).setCheckpoint(clientID, checkpoint);
    }


    readonly logger : logtape.Logger;

    #replicator?    : repl.Replicator;              // Actual replicator, while it's running
    #lastStatus     : repl.Status = {};             // Final status of the Replicator
}


class DelegateImpl {
    constructor(readonly replicator: Replicator, readonly collection: Collection, dir: string) {
        this.logger = replicator.logger.with({collection: collection.name, dir: dir});
    }

    protected readonly logger: logtape.Logger;
}


//-------- PUSHER DELEGATE:


class PusherDelegateImpl extends DelegateImpl implements repl.PusherDelegate {

    constructor(replicator: Replicator, collection: Collection,
                readonly config: repl.PusherConfig)
    {
        super(replicator, collection, 'push');
    }


    async getChanges(since: repl.LocalSequence | undefined,
                     limit: number): Promise<repl.PushRevision[]>
    {
        const collection = this.collection;
        const changes = await this.getDocsSinceSequence(since, limit);
        if (this.replicator.status.status === 'stopped')
            return [];
        if (changes.length > 0 || !this.config.continuous) {
            // Got changes; or in a non-continuous replication return the empty list as a signal
            // that there aren't any more:
            return changes;
        } else if (!this.#caughtUp) {
            // Pusher is in continuous mode and there are no more changes.
            // The first time this happens, return the empty list as a signal that it's caught up:
            this.#caughtUp = true;
            return changes;
        } else {
            // After that, use a 'collectionChanged' event listener to wait for changes to return:
            assert(!this.#asyncGetChanges);
            this.#asyncGetChanges = Promise.withResolvers<repl.PushRevision[]>();
            let listener: ListenerToken;
            const onChanges = () => {
                listener.remove(); // one-shot
                const resolve = this.#asyncGetChanges?.resolve;
                if (resolve) {
                    this.logger.info `Notifying Pusher of changes to collection ${collection.name}`;
                    this.#asyncGetChanges = undefined;
                    resolve(this.getDocsSinceSequence(since, limit));
                }
            };
            listener = collection.addChangeListener(onChanges);
            this.logger.info `Pusher is watching for changes to collection ${collection.name}`;
            return this.#asyncGetChanges.promise;
        }
    }


    private async getDocsSinceSequence(since: repl.LocalSequence | undefined,
                                       limit: number) : Promise<repl.PushRevision[]>
    {
        const changes = await this.collection.getDocsSinceSequence(since, limit);
        if (changes.length > 0 && (this.#pushedRevs || this.#updatingServerRevs)) {
            // Make sure their `serverRev`s are up to date, since those are updated asynchronously:
            for (const rev of changes) {
                const serverRev = this.#pushedRevs?.get(rev.id) ??
                                  this.#updatingServerRevs?.get(rev.id);
                if (greaterGeneration(serverRev, rev.serverRev))
                    rev.serverRev = serverRev;
            }
        }
        return changes;
    }


    async getBlob(digest: string): Promise<Uint8Array | undefined> {
        return await this.collection.database.blobStore.getBlob(digest);
    }


    pushedRev(rev: repl.PushRevision, error?: Error): void {
        if (!error) {
            // After pushing, update the document's `serverRev` to the pushed revID.
            // Do this asynchonously, in batches, to avoid a txn per doc pushed.
            let pushedRevs = this.#pushedRevs;
            if (!pushedRevs) {
                pushedRevs = new Map();
                this.#pushedRevs = pushedRevs;
            }
            pushedRevs.set(rev.id, rev.rev);
            this.updateServerRevsNow();
        }
        this.notifyDocEnded(rev, error);
    }

    private updateServerRevsNow() {
        let pushedRevs = this.#pushedRevs;
        if (pushedRevs && !this.#updatingServerRevs) {
            this.logger.debug `Updating serverRev property of ${pushedRevs.size} pushed docs`;
            this.#pushedRevs = undefined;
            this.#updatingServerRevs = pushedRevs;

            this.collection.updateServerRevs(pushedRevs).
                catch( error => this.logger.error `Error updating local serverRevs: ${error}`).
                finally( () => {
                    this.#updatingServerRevs = undefined;
                    // Update some more, if any have been added:
                    if (this.#pushedRevs)
                        this.updateServerRevsNow();
                });
        }
    }

    private notifyDocEnded(rev: repl.PushRevision, error?: Error) {
        if (this.replicator.onDocuments) {
            this.replicator.onDocuments(this.collection, 'push', [ {
                docID:   rev.id,
                deleted: !!rev.deleted,
                error:   error,
            } ] );
        }
    }


    #caughtUp            = false;
    #asyncGetChanges?    : PromiseWithResolvers<repl.PushRevision[]>;
    #pushedRevs?         : Map<DocID,RevID>;                    // docs whose serverRevIDs to update
    #updatingServerRevs? : Map<DocID,RevID>;                    // docs being updated right now
}


//-------- PULLER DELEGATE:


class PullerDelegateImpl extends DelegateImpl implements repl.PullerDelegate {

    constructor(replicator: Replicator, collection: Collection,
                readonly config: repl.PullerConfig,
                public startedEmpty: boolean)
    {
        super(replicator, collection, 'pull');
        this.blobLoader = this.collection.database.blobLoader;
    }

    readonly blobLoader: blob.BlobLoader;


    async wantRevs?(revs: repl.RemoteRevisionInfo[], caughtUp: boolean): Promise<void> {
        if (caughtUp)
            this.startedEmpty = false;
        else if (this.startedEmpty)
            return;

        const toBePurged: DocumentEnded[] = [];

        await this.collection.inTransaction(ReadOnly, async (coll) => {
            for (const rev of revs) {
                if (rev.lostAccess && !rev.deleted) {
                    rev.skip = true;
                    toBePurged.push({docID: rev.id, lostAccess: rev.lostAccess});
                } else if (!rev.skip) {
                    const knownRevs = await coll.getAncestorRevs(rev.id, rev.rev);
                    if (knownRevs)
                        rev.knownRevs = knownRevs;
                    else
                        rev.skip = true;
                }
            }
        });

        if (toBePurged.length > 0) {
            if (this.config.enableAutoPurge !== false) {
                await this.collection.purgeMultiple(toBePurged.map(d => d.docID));
            }
            this.replicator.onDocuments?.(this.collection, 'pull', toBePurged);
        }
    }


    async saveRevs(revs: repl.RemoteRevision[]): Promise<boolean> {
        const collection = this.collection;
        this.logger.debug `Collection ${collection.name} saving ${revs.length} documents...`;
        const now = Date.now();
        const {lastSequence, conflicts} = await collection.putRemoteRevisions(revs, this.startedEmpty);
        this.logger.info `Collection ${collection.name} saved ${revs.length} documents, ${conflicts?.size ?? 0} conflicts, as sequences thru ${lastSequence}, in ${Date.now() - now}ms`;

        if (this.replicator.onDocuments) {
            if (conflicts)
                revs = revs.filter( rev => !conflicts.has(rev.id) );
            const docs = revs.map( rev => ({docID: rev.id, deleted: !!rev.deleted}) );
            this.replicator.onDocuments(collection, 'pull', docs);
        }

        if (conflicts)
            void this.resolveConflicts(conflicts);
        return true;
    }


    async missingBlobs(digests: Set<string>): Promise<string[] | undefined> {
        let missing: string[] | undefined;
        for (const digest of digests) {
            if (!await this.collection.database.blobStore.hasBlob(digest)) {
                if (!missing) missing = [];
                missing.push(digest);
            }
        }
        return missing;
    }


    async addBlob(digest: string, contents: Uint8Array): Promise<void> {
        const gotDigest = blob.NewBlob.computeDigest(contents);
        if (digest !== gotDigest)
            throw new repl.ReplicatorError(`Requested blob digest '${digest}' but the data's digest is '${gotDigest}'`, 400);
        await this.collection.database.blobStore.saveBlob(contents, digest);
    }


    hasOnDocumentsCallback(): boolean {
        return !!this.replicator.onDocuments;
    }


    private async resolveConflicts(conflictIDs: Set<DocID>) {
        const collection = this.collection;
        const resolver = this.config.conflictResolver ?? defaultConflictResolver;
        for (const docID of conflictIDs) {
            try {
                let rev: LocalRevision | undefined;
                let resolved!: JSONObject | null;
                do {
                    rev = await collection.getRevision(docID, true);
                    const conflict = rev?.conflict;
                    if (rev === undefined || conflict === undefined)
                        break;
                    let local: Revision = {
                        id: rev.id,
                        rev: rev.rev,
                        deleted: revIsDeleted(rev) ? 1 : undefined,
                        body: rev.body };
                    let remote: Revision = {
                        id: rev.id,
                        rev: rev.serverRev!,
                        deleted: (conflict === null) ? 1 : undefined,
                        body: conflict ?? { },
                    };
                    const resolvedRev = await resolver(collection, local, remote);
                    resolved = (resolvedRev.deleted) ? null : resolvedRev.body;
                } while (!await collection.resolveConflict(docID, rev.rev, resolved));

                if (this.replicator.onDocuments) {
                    const doc = {docID: docID, deleted: (resolved === null)};
                    this.replicator.onDocuments(collection, 'pull', [doc]);
                }
            } catch (x) {
                this.logger.error `Exception resolving conflict in in ${collection.name} doc ${docID}: ${x}`;
            }
        }
    }
}


// eslint-disable-next-line @typescript-eslint/require-await
async function defaultConflictResolver(_collection: Collection,
                                       local: Revision,
                                       remote: Revision): Promise<Revision>
{
    if (local.deleted !== remote.deleted)
        return local.deleted ? local : remote;
    else if (greaterGeneration(local.rev, remote.rev))
        return local;
    else
        return remote;
}
